// Find the earliest Friday the 13th in the proleptic Gregorian calendar
// and count all Friday the 13ths in a full 400-year cycle.

// --- Earliest Friday the 13th starting from 0001-01-01 ---
DateOnly earliest = default;
for (int year = 1; year <= 400; year++)
{
    for (int month = 1; month <= 12; month++)
    {
        var d = new DateOnly(year, month, 13);
        if (d.DayOfWeek == DayOfWeek.Friday)
        {
            if (earliest == default)
            {
                earliest = d;
                Console.WriteLine($"Earliest Friday the 13th: {d:yyyy-MM-dd}");
            }
        }
    }
}

// --- Count in a full 400-year cycle (the Gregorian calendar repeats every 400 years) ---
int count = 0;
for (int year = 1; year <= 400; year++)
{
    for (int month = 1; month <= 12; month++)
    {
        var d = new DateOnly(year, month, 13);
        if (d.DayOfWeek == DayOfWeek.Friday)
            count++;
    }
}

Console.WriteLine($"Friday the 13ths in a 400-year cycle: {count}");
Console.WriteLine($"Average per year: {count / 400.0:F4}");

// --- Bonus: breakdown by month ---
Console.WriteLine("\nBreakdown by month (over 400 years):");
for (int month = 1; month <= 12; month++)
{
    int mc = 0;
    for (int year = 1; year <= 400; year++)
    {
        var d = new DateOnly(year, month, 13);
        if (d.DayOfWeek == DayOfWeek.Friday)
            mc++;
    }
    Console.WriteLine($"  {new DateOnly(2000, month, 1):MMMM,-12} {mc}");
}

